[SysClientCacheDataMethod]
public static boolean KPMGCommon_ExisteCredito_Caucion(CustAccount _AccounNum, TransDate _InvoiceDate)
{
    CredManCustGuaranteeInsurance custGuaranteeInsurance;
    CredManCreditMaxMST creditMax;
    boolean             existeCreditoCaucion = false;
    date                todaysDate = DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone());

    while select CreditLimitPercent, CurrencyCode, Value, IncludeInExposure from custGuaranteeInsurance
        where custGuaranteeInsurance.CustAccount == _AccounNum &&
              custGuaranteeInsurance.ValidFrom <= _InvoiceDate &&
              (!custGuaranteeInsurance.ValidTo || custGuaranteeInsurance.ValidTo >= _InvoiceDate)
    {
        creditMax += CurrencyExchangeHelper::mstAmount(custGuaranteeInsurance.CreditLimitPercent * custGuaranteeInsurance.Value / 100, custGuaranteeInsurance.CurrencyCode);
        if (custGuaranteeInsurance.IncludeInExposure == NoYes::Yes)
        {
            creditMax -= CurrencyExchangeHelper::mstAmount(custGuaranteeInsurance.Value, custGuaranteeInsurance.CurrencyCode);
        }
    }

    if (creditMax != 0)
        existeCreditoCaucion = true;

    return existeCreditoCaucion;
}
